import { useState, useRef, useCallback, useEffect } from "react";

type VapiStatus = "idle" | "connecting" | "active" | "error";

interface UseVapiReturn {
  status: VapiStatus;
  isSpeaking: boolean;
  transcript: string;
  startCall: () => Promise<void>;
  stopCall: () => void;
  sendMessage: (text: string) => void;
  error: string | null;
}

export function useVapi(): UseVapiReturn {
  const [status, setStatus] = useState<VapiStatus>("idle");
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [transcript, setTranscript] = useState("");
  const [error, setError] = useState<string | null>(null);
  const vapiRef = useRef<any>(null);

  const startCall = useCallback(async () => {
    try {
      setStatus("connecting");
      setError(null);

      // Fetch public key from backend
      const res = await fetch("/api/vapi-config", {
        headers: { Authorization: `Bearer ${(window as any).__supabaseToken || ""}` },
      });
      if (!res.ok) throw new Error("VAPI not configured on server");
      const { publicKey } = await res.json();
      if (!publicKey) throw new Error("VAPI public key missing");

      const { default: Vapi } = await import("@vapi-ai/web");
      const vapi = new Vapi(publicKey);
      vapiRef.current = vapi;

      vapi.on("call-start", () => {
        setStatus("active");
      });

      vapi.on("call-end", () => {
        setStatus("idle");
        setIsSpeaking(false);
      });

      vapi.on("speech-start", () => setIsSpeaking(true));
      vapi.on("speech-end", () => setIsSpeaking(false));

      vapi.on("message", (msg: any) => {
        if (msg.type === "transcript" && msg.transcript) {
          setTranscript(msg.transcript);
        }
      });

      vapi.on("error", (err: any) => {
        console.error("VAPI error:", err);
        setError(err?.message || "Voice call error");
        setStatus("error");
      });

      await vapi.start({
        name: "LENORY Voice Assistant",
        firstMessage: "Hello! I'm LENORY, your AI learning assistant. How can I help you today?",
        transcriber: {
          provider: "deepgram",
          model: "nova-2",
          language: "en",
        },
        voice: {
          provider: "11labs",
          voiceId: "rachel",
        },
        model: {
          provider: "openai",
          model: "gpt-3.5-turbo",
          messages: [
            {
              role: "system",
              content: `You are LENORY, an advanced AI tutor designed for Nigerian students. 
You help with JAMB, WAEC, NECO, and all academic subjects. 
You are conversational, encouraging, and adapt your explanations to the student's level.
Keep responses concise for voice — aim for 2-3 sentences unless asked to elaborate.
Speak naturally and clearly, as this is a voice conversation.`,
            },
          ],
        },
      });
    } catch (err: any) {
      console.error("VAPI start error:", err);
      setError(err?.message || "Failed to start voice call");
      setStatus("error");
    }
  }, []);

  const stopCall = useCallback(() => {
    if (vapiRef.current) {
      vapiRef.current.stop();
      vapiRef.current = null;
    }
    setStatus("idle");
    setIsSpeaking(false);
  }, []);

  const sendMessage = useCallback((text: string) => {
    if (vapiRef.current && status === "active") {
      vapiRef.current.send({ type: "add-message", message: { role: "user", content: text } });
    }
  }, [status]);

  useEffect(() => {
    return () => {
      if (vapiRef.current) {
        vapiRef.current.stop();
      }
    };
  }, []);

  return { status, isSpeaking, transcript, startCall, stopCall, sendMessage, error };
}

